1	/********************************************************************
2	 * This file includes functions to build bitstream from a mapped
3	 * FPGA fabric.
4	 * We decode the bitstream from configuration of routing multiplexers
5	 * and Look-Up Tables (LUTs) which locate in CLBs and global routing
6	 *architecture
7	 *******************************************************************/
8	#include <vector>
9	
10	/* Headers from vtrutil library */
11	#include "build_device_bitstream.h"
12	#include "build_grid_bitstream.h"
13	#include "build_routing_bitstream.h"
14	#include "memory_utils.h"
15	#include "module_manager_utils.h"
16	#include "openfpga_naming.h"
17	#include "vtr_assert.h"
18	#include "vtr_log.h"
19	#include "vtr_time.h"
20	
21	/* begin namespace openfpga */
22	namespace openfpga {
23	
24	/********************************************************************
25	 * Estimate the number of blocks to be added to the whole device bitstream
26	 * This function will recursively walk through the module graph
27	 * from the specified top module and count the number of configurable children
28	 * which are the blocks that will be added to the bitstream manager
29	 *******************************************************************/
30	static size_t rec_estimate_device_bitstream_num_blocks(
31	  const ModuleManager& module_manager, const ModuleId& top_module) {
32	  size_t num_blocks = 0;
33	
34	  /* Those child modules which have no children are
35	   * actually configurable memory elements
36	   * We skip them in couting
37	   */
38	  if (0 == module_manager.num_configurable_children(
39	             top_module, ModuleManager::e_config_child_type::PHYSICAL)) {
40	    return 0;
41	  }
42	
43	  size_t num_configurable_children =
44	    module_manager
45	      .configurable_children(top_module,
46	                             ModuleManager::e_config_child_type::PHYSICAL)
47	      .size();
48	  for (size_t ichild = 0; ichild < num_configurable_children; ++ichild) {
49	    ModuleId child_module = module_manager.configurable_children(
50	      top_module, ModuleManager::e_config_child_type::PHYSICAL)[ichild];
51	    num_blocks +=
52	      rec_estimate_device_bitstream_num_blocks(module_manager, child_module);
53	  }
54	
55	  /* Add the number of blocks at current level */
56	  num_blocks++;
57	
58	  return num_blocks;
59	}
60	
61	/********************************************************************
62	 * Estimate the number of configuration bits to be added to the whole device
63	 *bitstream This function will recursively walk through the module graph from
64	 *the specified top module and count the number of leaf configurable children
65	 * which are the bits that will be added to the bitstream manager
66	 *******************************************************************/
67	static size_t rec_estimate_device_bitstream_num_bits(
68	  const ModuleManager& module_manager, const ModuleId& top_module,
69	  const ModuleId& parent_module, const ConfigProtocol& config_protocol) {
70	  size_t num_bits = 0;
71	
72	  /* If a child module has no configurable children, this is a leaf node
73	   * We can count it in. Otherwise, we should go recursively.
74	   */
75	  if (0 == module_manager.num_configurable_children(
76	             parent_module, ModuleManager::e_config_child_type::PHYSICAL)) {
77	    return 1;
78	  }
79	
80	  /* Two cases to walk through configurable children:
81	   * - For top-level module:
82	   *   Iterate over the multiple regions and visit each configuration child
83	   * under any region In each region, frame-based configuration protocol or
84	   * memory bank protocol will contain decoders. We should bypass them when
85	   * count the bitstream size
86	   * - For other modules:
87	   *   Iterate over the configurable children regardless of regions
88	   */
89	  if (parent_module == top_module) {
90	    for (const ConfigRegionId& config_region :
91	         module_manager.regions(parent_module)) {
92	      size_t curr_region_num_config_child =
93	        module_manager
94	          .region_configurable_children(parent_module, config_region)
95	          .size();
96	      size_t num_child_to_skip =
97	        estimate_num_configurable_children_to_skip_by_config_protocol(
98	          config_protocol, curr_region_num_config_child);
99	      curr_region_num_config_child -= num_child_to_skip;
100	
101	      /* Visit all the children in a recursively way */
102	      for (size_t ichild = 0; ichild < curr_region_num_config_child; ++ichild) {
103	        ModuleId child_module = module_manager.region_configurable_children(
104	          parent_module, config_region)[ichild];
105	        num_bits += rec_estimate_device_bitstream_num_bits(
106	          module_manager, top_module, child_module, config_protocol);
107	      }
108	    }
109	  } else {
110	    VTR_ASSERT_SAFE(parent_module != top_module);
111	
112	    size_t num_configurable_children =
113	      module_manager
114	        .configurable_children(parent_module,
115	                               ModuleManager::e_config_child_type::PHYSICAL)
116	        .size();
117	
118	    /* Frame-based configuration protocol will have 1 decoder
119	     * if there are more than 1 configurable children
120	     */
121	    if ((CONFIG_MEM_FRAME_BASED == config_protocol.type()) &&
122	        (2 <= num_configurable_children)) {
123	      num_configurable_children--;
124	    }
125	
126	    for (size_t ichild = 0; ichild < num_configurable_children; ++ichild) {
127	      ModuleId child_module = module_manager.configurable_children(
128	        parent_module, ModuleManager::e_config_child_type::PHYSICAL)[ichild];
129	      num_bits += rec_estimate_device_bitstream_num_bits(
130	        module_manager, top_module, child_module, config_protocol);
131	    }
132	  }
133	
134	  return num_bits;
135	}
136	
137	/********************************************************************
138	 * A top-level function to build a bistream from the FPGA device
139	 * 1. It will organize the bitstream w.r.t. the hierarchy of module graphs
140	 *    describing the FPGA fabric
141	 * 2. It will decode configuration bits from routing multiplexers used in
142	 *    global routing architecture
143	 * 3. It will decode configuration bits from routing multiplexers and LUTs
144	 *    used in CLBs
145	 *
146	 * Note: this function create a bitstream which is binding to the module graphs
147	 * of the FPGA fabric that FPGA-X2P generates!
148	 * But it can be used to output a generic bitstream for VPR mapping FPGA
149	 *******************************************************************/
150	BitstreamManager build_device_bitstream(const VprContext& vpr_ctx,
151	                                        const OpenfpgaContext& openfpga_ctx,
152	                                        const std::string& unused_mux_config,
153	                                        const bool& verbose) {
154	  std::string timer_message =
155	    std::string("\nBuild fabric-independent bitstream for implementation '") +
156	    vpr_ctx.atom().netlist().netlist_name() + std::string("'\n");
157	  vtr::ScopedStartFinishTimer timer(timer_message);
158	
159	  /* Bitstream manager to be built */
160	  BitstreamManager bitstream_manager;
161	
162	  /* Create the top-level block for bitstream
163	   * This is related to the top-level module of fpga
164	   */
165	  std::string top_block_name =
166	    openfpga_ctx.module_name_map().name(generate_fpga_top_module_name());
167	  ConfigBlockId top_block = bitstream_manager.add_block(top_block_name);
168	  ModuleId top_module = openfpga_ctx.module_graph().find_module(top_block_name);
169	  VTR_ASSERT(true == openfpga_ctx.module_graph().valid_module_id(top_module));
170	
171	  /* Create the core block when the fpga_core is added */
172	  size_t num_blocks_to_reserve = 0;
173	  std::string core_block_name = generate_fpga_core_module_name();
174	  if (openfpga_ctx.module_name_map().name_exist(core_block_name)) {
175	    core_block_name = openfpga_ctx.module_name_map().name(core_block_name);
176	  }
177	  const ModuleId& core_module =
178	    openfpga_ctx.module_graph().find_module(core_block_name);
179	  if (openfpga_ctx.module_graph().valid_module_id(core_module)) {
180	    std::string core_inst_name =
181	      openfpga_ctx.module_graph().instance_name(top_module, core_module, 0);
182	    ConfigBlockId core_block = bitstream_manager.add_block(core_inst_name);
183	    bitstream_manager.add_child_block(top_block, core_block);
184	    /* Now we use the core_block as the top-level block for the remaining
185	     * functions */
186	    top_module = core_module;
187	    top_block = core_block;
188	    /* Count in fpga core as a block to reserve */
189	    num_blocks_to_reserve += 1;
190	  }
191	
192	  /* Estimate the number of blocks to be added to the database */
193	  num_blocks_to_reserve += rec_estimate_device_bitstream_num_blocks(
194	    openfpga_ctx.module_graph(), top_module);
195	  bitstream_manager.reserve_blocks(num_blocks_to_reserve);
196	  VTR_LOGV(verbose, "Reserved %lu configurable blocks\n",
197	           num_blocks_to_reserve);
198	
199	  /* Estimate the number of bits to be added to the database */
200	  size_t num_bits_to_reserve = rec_estimate_device_bitstream_num_bits(
201	    openfpga_ctx.module_graph(), top_module, top_module,
202	    openfpga_ctx.arch().config_protocol);
203	  bitstream_manager.reserve_bits(num_bits_to_reserve);
204	  VTR_LOGV(verbose, "Reserved %lu configuration bits\n", num_bits_to_reserve);
205	
206	  /* Reserve child blocks for the top level block */
207	  bitstream_manager.reserve_child_blocks(
208	    top_block, count_module_manager_module_configurable_children(
209	                 openfpga_ctx.module_graph(), top_module,
210	                 ModuleManager::e_config_child_type::PHYSICAL));
211	
212	  /* Create bitstream from grids */
213	  VTR_LOGV(verbose, "Building grid bitstream...\n");
214	  RRGraphInEdges in_edges;
215	  in_edges.init(vpr_ctx.device().rr_graph);
216	
217	  build_grid_bitstream(
218	    bitstream_manager, top_block, openfpga_ctx.module_graph(),
219	    openfpga_ctx.module_name_map(), openfpga_ctx.fabric_tile(),
220	    openfpga_ctx.arch().circuit_lib, openfpga_ctx.mux_lib(),
221	    vpr_ctx.device().grid, 0, vpr_ctx.atom(),
222	    openfpga_ctx.vpr_device_annotation(),
223	    openfpga_ctx.vpr_clustering_annotation(),
224	    openfpga_ctx.vpr_placement_annotation(),
225	    openfpga_ctx.vpr_bitstream_annotation(), unused_mux_config, verbose);
226	  VTR_LOGV(verbose, "Done\n");
227	
228	  /* Create bitstream from routing architectures */
229	  VTR_LOGV(verbose, "Building routing bitstream...\n");
230	  build_routing_bitstream(
231	    bitstream_manager, top_block, openfpga_ctx.module_graph(),
232	    openfpga_ctx.module_name_map(), openfpga_ctx.fabric_tile(),
233	    openfpga_ctx.arch().circuit_lib, openfpga_ctx.mux_lib(), vpr_ctx.atom(),
234	    openfpga_ctx.vpr_device_annotation(), openfpga_ctx.vpr_routing_annotation(),
235	    vpr_ctx.device().rr_graph, in_edges, openfpga_ctx.device_rr_gsb(),
236	    openfpga_ctx.flow_manager().compress_routing(), unused_mux_config, verbose);
237	
238	  VTR_LOGV(verbose, "Done\n");
239	
240	  VTR_LOGV(verbose, "Decoded %lu configuration bits into %lu blocks\n",
241	           bitstream_manager.num_bits(), bitstream_manager.num_blocks());
242	
243	  VTR_ASSERT(num_blocks_to_reserve == bitstream_manager.num_blocks());
244	  VTR_ASSERT(num_bits_to_reserve == bitstream_manager.num_bits());
245	
246	  return bitstream_manager;
247	}
248	
249	} /* end namespace openfpga */
