1	#ifndef OPENFPGA_BITSTREAM_TEMPLATE_H
2	#define OPENFPGA_BITSTREAM_TEMPLATE_H
3	
4	/********************************************************************
5	 * This file includes functions to build bitstream database
6	 *******************************************************************/
7	#include "bitstream_writer_options.h"
8	#include "build_device_bitstream.h"
9	#include "build_fabric_bitstream.h"
10	#include "build_io_mapping_info.h"
11	#include "command.h"
12	#include "command_context.h"
13	#include "command_exit_codes.h"
14	#include "extract_device_non_fabric_bitstream.h"
15	#include "globals.h"
16	#include "openfpga_digest.h"
17	#include "openfpga_naming.h"
18	#include "openfpga_reserved_words.h"
19	#include "overwrite_bitstream.h"
20	#include "read_xml_arch_bitstream.h"
21	#include "report_bitstream_distribution.h"
22	#include "vtr_log.h"
23	#include "vtr_time.h"
24	#include "write_text_fabric_bitstream.h"
25	#include "write_xml_arch_bitstream.h"
26	#include "write_xml_fabric_bitstream.h"
27	#include "write_xml_io_mapping.h"
28	
29	/* begin namespace openfpga */
30	namespace openfpga {
31	
32	/********************************************************************
33	 * A wrapper function to call the build_device_bitstream() in FPGA bitstream
34	 *******************************************************************/
35	template <class T>
36	int fpga_bitstream_template(T& openfpga_ctx, const Command& cmd,
37	                            const CommandContext& cmd_context) {
38	  CommandOptionId opt_verbose = cmd.option("verbose");
39	  CommandOptionId opt_no_time_stamp = cmd.option("no_time_stamp");
40	  CommandOptionId opt_write_file = cmd.option("write_file");
41	  CommandOptionId opt_read_file = cmd.option("read_file");
42	  CommandOptionId opt_unused_mux_config = cmd.option("unused_mux_config");
43	
44	  if (true == cmd_context.option_enable(cmd, opt_read_file)) {
45	    openfpga_ctx.mutable_bitstream_manager() = read_xml_architecture_bitstream(
46	      cmd_context.option_value(cmd, opt_read_file).c_str());
47	  } else {
48	    std::string unused_mux_config;
49	    unused_mux_config = cmd_context.option_enable(cmd, opt_unused_mux_config)
50	                          ? cmd_context.option_value(cmd, opt_unused_mux_config)
51	                          : "auto";
52	
53	    if (unused_mux_config != "auto" && unused_mux_config != "first" &&
54	        unused_mux_config != "last" && unused_mux_config != "unused_input") {
55	      VTR_LOG_ERROR(
56	        "Invalid unused_mux_config '%s'. Must be 'auto', 'first', 'last', or "
57	        "'unused_input'!\n",
58	        unused_mux_config.c_str());
59	      return CMD_EXEC_FATAL_ERROR;
60	    }
