246	/********************************************************************
247	 * Find the mux path id (the index of the selected input) for the mux that
248	 * drives a given destination pin, based on the routing results stored in
249	 * physical_pb. Returns DEFAULT_PATH_ID when the destination is unmapped, has no
250	 * net, or none of the mux inputs carries the destination's net.
251	 *******************************************************************/
252	static int find_physical_block_pin_mux_path_id(const PhysicalPb& physical_pb,
253	                                               t_pb_graph_pin* des_pb_graph_pin,
254	                                               t_interconnect* cur_interc,
255	                                               const size_t& fan_in) {
256	  const PhysicalPbId& des_pb_id =
257	    physical_pb.find_pb(des_pb_graph_pin->parent_node);
258	  if (true != physical_pb.valid_pb_id(des_pb_id)) {
259	    return DEFAULT_PATH_ID;
260	  }
261	  AtomNetId output_net =
262	    physical_pb.pb_graph_pin_atom_net(des_pb_id, des_pb_graph_pin);
263	  if (AtomNetId::INVALID() == output_net) {
264	    return DEFAULT_PATH_ID;
265	  }
266	  size_t mux_input_pin_id = 0;
267	  for (t_pb_graph_pin* src_pb_graph_pin :
268	       pb_graph_pin_inputs(des_pb_graph_pin, cur_interc)) {
269	    const PhysicalPbId& src_pb_id =
270	      physical_pb.find_pb(src_pb_graph_pin->parent_node);
271	    /* If the src pb id is not valid, we bypass it */
272	    if ((true == physical_pb.valid_pb_id(src_pb_id)) &&
273	        (physical_pb.pb_graph_pin_atom_net(src_pb_id, src_pb_graph_pin) ==
274	         output_net)) {
275	      break;
276	    }
277	    mux_input_pin_id++;
278	  }
279	  VTR_ASSERT(mux_input_pin_id <= fan_in);
280	  /* Unmapped pin, use default path id */
281	  if (fan_in == mux_input_pin_id) {
282	    return DEFAULT_PATH_ID;
283	  }
284	  return (int)mux_input_pin_id;
285	}
