287	/********************************************************************
288	 * This function generates bitstream for a programmable routing
289	 * multiplexer which drives an output pin of physical_pb_graph_node and its the
290	 *input_edges
291	 *
292	 *   src_pb_graph_node.[in|out]_pins ----------------->
293	 *des_pb_graph_node.[in|out]pins
294	 *                                        /|\
295	 *                                         |
296	 *                         input_pins,   edges,       output_pins
297	 *******************************************************************/
298	static void build_physical_block_pin_interc_bitstream(
299	  BitstreamManager& bitstream_manager,
300	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
301	  const ConfigBlockId& parent_configurable_block,
302	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
303	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
304	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
305	  const VprBitstreamAnnotation& bitstream_annotation,
306	  const PhysicalPb& physical_pb, t_pb_graph_pin* des_pb_graph_pin,
307	  t_mode* physical_mode, const std::string& unused_mux_config,
308	  const bool& verbose) {
309	  /* Identify the number of fan-in (Consider interconnection edges of only
310	   * selected mode) */
311	  t_interconnect* cur_interc =
312	    pb_graph_pin_interc(des_pb_graph_pin, physical_mode);
313	  size_t fan_in = pb_graph_pin_inputs(des_pb_graph_pin, cur_interc).size();
314	
315	  if ((nullptr == cur_interc) || (0 == fan_in)) {
316	    /* No interconnection matched */
317	    return;
318	  }
319	
320	  /* Identify pin interconnection type */
321	  enum e_interconnect interc_type =
322	    device_annotation.interconnect_physical_type(cur_interc);
323	  switch (interc_type) {
324	    case DIRECT_INTERC:
325	      /* Nothing to do, return */
326	      break;
327	    case COMPLETE_INTERC:
328	    case MUX_INTERC: {
329	      /* Find the circuit model id of the mux, we need its design technology
330	       * which matters the bitstream generation */
331	      CircuitModelId mux_model =
332	        device_annotation.interconnect_circuit_model(cur_interc);
333	      VTR_ASSERT(CIRCUIT_MODEL_MUX == circuit_lib.model_type(mux_model));
334	
335	      /* Find the input size of the implementation of a routing multiplexer */
336	      size_t datapath_mux_size = fan_in;
337	      VTR_ASSERT(true ==
338	                 valid_mux_implementation_num_inputs(datapath_mux_size));
339	
340	      /* Cache input and output nets */
341	      std::vector<AtomNetId> input_nets;
342	      AtomNetId output_net = AtomNetId::INVALID();
343	
344	      /* Determine the representative pin used to name shared resources. For a
345	       * bus-based mux all the bits of the output bus share a single selector
346	       * (one memory block), named after the lowest-index bit. Only that
347	       * representative bit emits a bitstream block; the other bits are handled
348	       * together with it and skipped here. */
349	      t_pb_graph_pin* rep_pb_graph_pin = des_pb_graph_pin;
350	      size_t mux_input_pin_id = 0;
351	      /* Pin whose input/output nets are recorded for reporting. For a
352	       * partially mapped bus, the representative bit may be unused; prefer the
353	       * first mapped bit instead (updated in the loop below) */
354	      t_pb_graph_pin* net_pb_graph_pin = des_pb_graph_pin;
355	
356	      if (true == cur_interc->bus) {
357	        std::vector<t_pb_graph_pin*> bus_pins = pb_graph_interc_sink_pins(
358	          des_pb_graph_pin, cur_interc, physical_mode);
359	        VTR_ASSERT(false == bus_pins.empty());
360	        rep_pb_graph_pin = bus_pins.front();
361	        /* Only the representative bit emits the shared bitstream block */
362	        if (des_pb_graph_pin != rep_pb_graph_pin) {
363	          return;
364	        }
365	        /* All the mapped bits of the bus must select the same input port,
366	         * otherwise the bus mux cannot be realized with a single shared
367	         * selector. The path id equals the selected input-port index. */
368	        int bus_path_id = DEFAULT_PATH_ID;
369	        for (t_pb_graph_pin* bus_pin : bus_pins) {
370	          int pin_path_id = find_physical_block_pin_mux_path_id(
371	            physical_pb, bus_pin, cur_interc, fan_in);
372	          if (DEFAULT_PATH_ID == pin_path_id) {
373	            continue;
374	          }
375	          if (DEFAULT_PATH_ID == bus_path_id) {
376	            bus_path_id = pin_path_id;
377	            net_pb_graph_pin = bus_pin;
378	          } else if (bus_path_id != pin_path_id) {
379	            VTR_LOGF_ERROR(
380	              __FILE__, __LINE__,
381	              "Bus-based mux '%s' (Arch[LINE%d]) requires all bits of the "
382	              "output bus to be routed from the same input port. Bit '%s' "
383	              "selects input %d while another bit of the same bus selects "
384	              "input %d. Check the packing/routing results.\n",
385	              cur_interc->name, cur_interc->line_num,
386	              bus_pin->to_string().c_str(), pin_path_id, bus_path_id);
387	            exit(CMD_EXEC_FATAL_ERROR);
388	          }
389	        }
390	        mux_input_pin_id = (DEFAULT_PATH_ID == bus_path_id)
391	                             ? size_t(DEFAULT_PATH_ID)
392	                             : size_t(bus_path_id);
393	      } else {
394	        int pin_path_id = find_physical_block_pin_mux_path_id(
395	          physical_pb, des_pb_graph_pin, cur_interc, fan_in);
396	        mux_input_pin_id = (DEFAULT_PATH_ID == pin_path_id)
397	                             ? size_t(DEFAULT_PATH_ID)
398	                             : size_t(pin_path_id);
399	      }
400	
401	      /* Record input/output nets for reporting. For a bus-based mux, nets are
402	       * taken from the first mapped bit, since the representative bit may be
403	       * unused when the bus is partially mapped */
404	      const PhysicalPbId& net_pb_id =
405	        physical_pb.find_pb(net_pb_graph_pin->parent_node);
406	      if (true == physical_pb.valid_pb_id(net_pb_id)) {
407	        output_net =
408	          physical_pb.pb_graph_pin_atom_net(net_pb_id, net_pb_graph_pin);
409	        if (AtomNetId::INVALID() != output_net) {
410	          for (t_pb_graph_pin* src_pb_graph_pin :
411	               pb_graph_pin_inputs(net_pb_graph_pin, cur_interc)) {
412	            const PhysicalPbId& src_pb_id =
413	              physical_pb.find_pb(src_pb_graph_pin->parent_node);
414	            input_nets.push_back(
415	              physical_pb.pb_graph_pin_atom_net(src_pb_id, src_pb_graph_pin));
416	          }
417	        }
418	      }
419	
420	      /* Overwrite the default path if defined in bitstream annotation */
421	      if ((size_t(DEFAULT_PATH_ID) == mux_input_pin_id) &&
422	          (mux_input_pin_id !=
423	           bitstream_annotation.interconnect_default_path_id(cur_interc))) {
424	        mux_input_pin_id =
425	          bitstream_annotation.interconnect_default_path_id(cur_interc);
426	      }
427	
428	      /* Generate bitstream depend on both technology and structure of this MUX
429	       */
430	      std::vector<bool> mux_bitstream =
431	        build_mux_bitstream(circuit_lib, mux_model, mux_lib, datapath_mux_size,
432	                            mux_input_pin_id, unused_mux_config);
433	
434	      /* Create the block denoting the memory instances that drives this node in
435	       * physical_block. For a bus-based mux this is the shared memory named
436	       * after the representative bit, so it matches the fabric module. */
437	      std::string mem_block_name = generate_pb_memory_instance_name(
438	        GRID_MEM_INSTANCE_PREFIX, rep_pb_graph_pin, std::string(""));
439	
440	      /* Find the module in module manager and ensure the bitstream size
441	       * matches! */
442	      std::string mem_module_name =
443	        generate_mux_subckt_name(circuit_lib, mux_model, datapath_mux_size,
444	                                 std::string(MEMORY_MODULE_POSTFIX));
445	      mem_module_name = module_name_map.name(mem_module_name);
446	      ModuleId mux_mem_module = module_manager.find_module(mem_module_name);
447	      VTR_ASSERT(true == module_manager.valid_module_id(mux_mem_module));
448	      ModulePortId mux_mem_out_port_id = module_manager.find_module_port(
449	        mux_mem_module, generate_configurable_memory_data_out_name());
450	      VTR_ASSERT(mux_bitstream.size() ==
451	                 module_manager.module_port(mux_mem_module, mux_mem_out_port_id)
452	                   .get_width());
453	
454	      /* If there is a feedthrough module, we should consider the scoreboard */
455	      std::string feedthru_mem_block_name = generate_mux_subckt_name(
456	        circuit_lib, mux_model, datapath_mux_size,
457	        std::string(MEMORY_FEEDTHROUGH_MODULE_POSTFIX));
458	      if (module_name_map.name_exist(feedthru_mem_block_name)) {
459	        feedthru_mem_block_name = module_name_map.name(feedthru_mem_block_name);
460	      }
461	      ModuleId feedthru_mem_module =
462	        module_manager.find_module(feedthru_mem_block_name);
463	      if (module_manager.valid_module_id(feedthru_mem_module)) {
464	        auto result = grouped_mem_inst_scoreboard.find(mem_block_name);
465	        if (result == grouped_mem_inst_scoreboard.end()) {
466	          /* Update scoreboard */
467	          grouped_mem_inst_scoreboard[mem_block_name] = 0;
468	        } else {
469	          grouped_mem_inst_scoreboard[mem_block_name]++;
470	          mem_block_name = generate_instance_name(
471	            mem_block_name, grouped_mem_inst_scoreboard[mem_block_name]);
472	        }
473	      }
474	      ConfigBlockId mux_mem_block = bitstream_manager.add_block(mem_block_name);
475	      bitstream_manager.add_child_block(parent_configurable_block,
476	                                        mux_mem_block);
477	
478	      VTR_LOGV(verbose, "Added %lu bits to '%s' under '%s'\n",
479	               mux_bitstream.size(),
480	               bitstream_manager.block_name(mux_mem_block).c_str(),
481	               bitstream_manager.block_name(parent_configurable_block).c_str());
482	
483	      /* Add the bistream to the bitstream manager */
484	      bitstream_manager.add_block_bits(mux_mem_block, mux_bitstream);
485	      /* Record path ids, input and output nets */
486	      bitstream_manager.add_path_id_to_block(mux_mem_block, mux_input_pin_id);
487	
488	      /* Add input nets */
489	      std::string input_net_ids;
490	
491	      bool need_splitter = false;
492	      for (const AtomNetId& input_net : input_nets) {
493	        /* Add a space as a splitter*/
494	        if (true == need_splitter) {
495	          input_net_ids += std::string(" ");
496	        }
497	        if (true == atom_ctx.netlist().valid_net_id(input_net)) {
498	          input_net_ids += atom_ctx.netlist().net_name(input_net);
499	        } else {
500	          input_net_ids += std::string("unmapped");
501	        }
502	        need_splitter = true;
503	      }
504	      bitstream_manager.add_input_net_id_to_block(mux_mem_block, input_net_ids);
505	
506	      /* Add output nets */
507	      std::string output_net_ids;
508	      if (true == atom_ctx.netlist().valid_net_id(output_net)) {
509	        output_net_ids += atom_ctx.netlist().net_name(output_net);
510	      } else {
511	        output_net_ids += std::string("unmapped");
512	      }
513	      bitstream_manager.add_output_net_id_to_block(mux_mem_block,
514	                                                   output_net_ids);
515	
516	      break;
517	    }
518	    default:
519	      VTR_LOGF_ERROR(__FILE__, __LINE__,
520	                     "Invalid interconnection type for %s (Arch[LINE%d])!\n",
521	                     cur_interc->name.c_str(), cur_interc->line_num);
522	      exit(1);
523	  }
524	}
