526	/********************************************************************
527	 * This function generates bitstream for the programmable routing
528	 * multiplexers in a pb_graph node
529	 *******************************************************************/
530	static void build_physical_block_interc_port_bitstream(
531	  BitstreamManager& bitstream_manager,
532	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
533	  const ConfigBlockId& parent_configurable_block,
534	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
535	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
536	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
537	  const VprBitstreamAnnotation& bitstream_annotation,
538	  t_pb_graph_node* physical_pb_graph_node, const PhysicalPb& physical_pb,
539	  const e_circuit_pb_port_type& pb_port_type, t_mode* physical_mode,
540	  const std::string& unused_mux_config, const bool& verbose) {
541	  switch (pb_port_type) {
542	    case CIRCUIT_PB_PORT_INPUT:
543	      for (int iport = 0; iport < physical_pb_graph_node->num_input_ports;
544	           ++iport) {
545	        for (int ipin = 0; ipin < physical_pb_graph_node->num_input_pins[iport];
546	             ++ipin) {
547	          build_physical_block_pin_interc_bitstream(
548	            bitstream_manager, grouped_mem_inst_scoreboard,
549	            parent_configurable_block, module_manager, module_name_map,
550	            circuit_lib, mux_lib, atom_ctx, device_annotation,
551	            bitstream_annotation, physical_pb,
552	            &(physical_pb_graph_node->input_pins[iport][ipin]), physical_mode,
553	            unused_mux_config, verbose);
554	        }
555	      }
556	      break;
557	    case CIRCUIT_PB_PORT_OUTPUT:
558	      for (int iport = 0; iport < physical_pb_graph_node->num_output_ports;
559	           ++iport) {
560	        for (int ipin = 0;
561	             ipin < physical_pb_graph_node->num_output_pins[iport]; ++ipin) {
562	          build_physical_block_pin_interc_bitstream(
563	            bitstream_manager, grouped_mem_inst_scoreboard,
564	            parent_configurable_block, module_manager, module_name_map,
565	            circuit_lib, mux_lib, atom_ctx, device_annotation,
566	            bitstream_annotation, physical_pb,
567	            &(physical_pb_graph_node->output_pins[iport][ipin]), physical_mode,
568	            unused_mux_config, verbose);
569	        }
570	      }
571	      break;
572	    case CIRCUIT_PB_PORT_CLOCK:
573	      for (int iport = 0; iport < physical_pb_graph_node->num_clock_ports;
574	           ++iport) {
575	        for (int ipin = 0; ipin < physical_pb_graph_node->num_clock_pins[iport];
576	             ++ipin) {
577	          build_physical_block_pin_interc_bitstream(
578	            bitstream_manager, grouped_mem_inst_scoreboard,
579	            parent_configurable_block, module_manager, module_name_map,
580	            circuit_lib, mux_lib, atom_ctx, device_annotation,
581	            bitstream_annotation, physical_pb,
582	            &(physical_pb_graph_node->clock_pins[iport][ipin]), physical_mode,
583	            unused_mux_config, verbose);
584	        }
585	      }
586	      break;
587	    default:
588	      VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid pb port type!\n");
589	      exit(1);
590	  }
591	}
