593	/********************************************************************
594	 * This function generates bitstream for the programmable routing
595	 * multiplexers in a pb_graph node
596	 *******************************************************************/
597	static void build_physical_block_interc_bitstream(
598	  BitstreamManager& bitstream_manager,
599	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
600	  const ConfigBlockId& parent_configurable_block,
601	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
602	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
603	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
604	  const VprBitstreamAnnotation& bitstream_annotation,
605	  t_pb_graph_node* physical_pb_graph_node, const PhysicalPb& physical_pb,
606	  t_mode* physical_mode, const std::string& unused_mux_config,
607	  const bool& verbose) {
608	  /* Check if the pb_graph node is valid or not */
609	  if (nullptr == physical_pb_graph_node) {
610	    VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid physical_pb_graph_node.\n");
611	    exit(1);
612	  }
613	
614	  /* We check output_pins of physical_pb_graph_node and its the input_edges
615	   * Iterate over the interconnections between outputs of physical_pb_graph_node
616	   * and outputs of child_pb_graph_node
617	   *   child_pb_graph_node.output_pins ----------------->
618	   * physical_pb_graph_node.outpins
619	   *                                        /|\
620	   *                                         |
621	   *                         input_pins,   edges,       output_pins
622	   * Note: it is not applied to primitive pb_type!
623	   */
624	  build_physical_block_interc_port_bitstream(
625	    bitstream_manager, grouped_mem_inst_scoreboard, parent_configurable_block,
626	    module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
627	    device_annotation, bitstream_annotation, physical_pb_graph_node,
628	    physical_pb, CIRCUIT_PB_PORT_OUTPUT, physical_mode, unused_mux_config,
629	    verbose);
630	
631	  /* We check input_pins of child_pb_graph_node and its the input_edges
632	   * Iterate over the interconnections between inputs of physical_pb_graph_node
633	   * and inputs of child_pb_graph_node
634	   *   physical_pb_graph_node.input_pins ----------------->
635	   * child_pb_graph_node.input_pins
636	   *                                        /|\
637	   *                                         |
638	   *                         input_pins,   edges,       output_pins
639	   */
640	  for (int ipb = 0; ipb < physical_mode->num_pb_type_children; ipb++) {
641	    for (int jpb = 0; jpb < physical_mode->pb_type_children[ipb].num_pb;
642	         jpb++) {
643	      t_pb_graph_node* child_pb_graph_node =
644	        &(physical_pb_graph_node
645	            ->child_pb_graph_nodes[physical_mode->index][ipb][jpb]);
646	
647	      /* For each child_pb_graph_node input pins*/
648	      build_physical_block_interc_port_bitstream(
649	        bitstream_manager, grouped_mem_inst_scoreboard,
650	        parent_configurable_block, module_manager, module_name_map, circuit_lib,
651	        mux_lib, atom_ctx, device_annotation, bitstream_annotation,
652	        child_pb_graph_node, physical_pb, CIRCUIT_PB_PORT_INPUT, physical_mode,
653	        unused_mux_config, verbose);
654	      /* For clock pins, we should do the same work */
655	      build_physical_block_interc_port_bitstream(
656	        bitstream_manager, grouped_mem_inst_scoreboard,
657	        parent_configurable_block, module_manager, module_name_map, circuit_lib,
658	        mux_lib, atom_ctx, device_annotation, bitstream_annotation,
659	        child_pb_graph_node, physical_pb, CIRCUIT_PB_PORT_CLOCK, physical_mode,
660	        unused_mux_config, verbose);
661	    }
662	  }
663	}
