665	/********************************************************************
666	 * Generate bitstream for a LUT and add it to bitstream manager
667	 * This function supports both single-output and fracturable LUTs
668	 *******************************************************************/
669	static void build_lut_bitstream(
670	  BitstreamManager& bitstream_manager,
671	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
672	  const ConfigBlockId& parent_configurable_block,
673	  const VprDeviceAnnotation& device_annotation,
674	  const ModuleManager& module_manager, const CircuitLibrary& circuit_lib,
675	  const MuxLibrary& mux_lib, const PhysicalPb& physical_pb,
676	  const PhysicalPbId& lut_pb_id, t_pb_type* lut_pb_type, const bool& verbose) {
677	  /* Ensure a valid physical pritimive pb */
678	  if (nullptr == lut_pb_type) {
679	    VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid lut_pb_type!\n");
680	    exit(1);
681	  }
682	
683	  CircuitModelId lut_model =
684	    device_annotation.pb_type_circuit_model(lut_pb_type);
685	  VTR_ASSERT(CircuitModelId::INVALID() != lut_model);
686	  VTR_ASSERT(CIRCUIT_MODEL_LUT == circuit_lib.model_type(lut_model));
687	
688	  /* Find the input ports for LUT size, this is used to decode the LUT memory
689	   * bits! */
690	  std::vector<CircuitPortId> model_input_ports =
691	    find_lut_circuit_model_input_port(circuit_lib, lut_model, false);
692	  VTR_ASSERT(1 == model_input_ports.size());
693	  size_t lut_size = circuit_lib.port_size(model_input_ports[0]);
694	
695	  /* Find SRAM ports for truth tables and mode-selection */
696	  std::vector<CircuitPortId> lut_regular_sram_ports =
697	    find_circuit_regular_sram_ports(circuit_lib, lut_model);
698	  std::vector<CircuitPortId> lut_mode_select_ports =
699	    find_circuit_mode_select_sram_ports(circuit_lib, lut_model);
700	  /* We should always 1 regular sram port, where truth table is loaded to */
701	  VTR_ASSERT(1 == lut_regular_sram_ports.size());
702	  /* We may have a port for mode select or not. This depends on if the LUT is
703	   * fracturable or not */
704	  VTR_ASSERT((0 == lut_mode_select_ports.size()) ||
705	             (1 == lut_mode_select_ports.size()));
706	
707	  std::vector<bool> lut_bitstream;
708	  /* Generate bitstream for the LUT */
709	  if (false == physical_pb.valid_pb_id(lut_pb_id)) {
710	    /* An empty pb means that this is an unused LUT,
711	     * we give an empty truth table, which are full of default values (defined
712	     * by users)
713	     */
714	    for (size_t i = 0; i < circuit_lib.port_size(lut_regular_sram_ports[0]);
715	         ++i) {
716	      VTR_ASSERT(
717	        (0 == circuit_lib.port_default_value(lut_regular_sram_ports[0])) ||
718	        (1 == circuit_lib.port_default_value(lut_regular_sram_ports[0])));
719	      lut_bitstream.push_back(
720	        1 == circuit_lib.port_default_value(lut_regular_sram_ports[0]));
721	    }
722	  } else {
723	    VTR_ASSERT(true == physical_pb.valid_pb_id(lut_pb_id));
724	
725	    /* Find MUX graph correlated to the LUT */
726	    MuxId lut_mux_id = mux_lib.mux_graph(lut_model, (size_t)pow(2., lut_size));
727	    const MuxGraph& mux_graph = mux_lib.mux_graph(lut_mux_id);
728	    /* Ensure the LUT MUX has the expected input and SRAM port sizes */
729	    VTR_ASSERT(mux_graph.num_memory_bits() == lut_size);
730	    VTR_ASSERT(mux_graph.num_inputs() == (size_t)pow(2., lut_size));
731	    /* Generate LUT bitstream */
732	    lut_bitstream = build_frac_lut_bitstream(
733	      circuit_lib, mux_graph, device_annotation,
734	      physical_pb.truth_tables(lut_pb_id),
735	      circuit_lib.port_default_value(lut_regular_sram_ports[0]));
736	    /* If the physical pb contains fixed bitstream, overload here */
737	    for (const auto& fix_bitstrm : physical_pb.fixed_bitstreams(lut_pb_id)) {
738	      std::string fixed_bitstream = fix_bitstrm.content;
739	      size_t start_index = fix_bitstrm.offset;
740	      /* Ensure the length matches!!! */
741	      if (lut_bitstream.size() - start_index < fixed_bitstream.size()) {
742	        VTR_LOG_ERROR(
743	          "Unmatched length of fixed bitstream %s!Expected to be less than %ld "
744	          "bits\n",
745	          fixed_bitstream.c_str(), lut_bitstream.size() - start_index);
746	        exit(1);
747	      }
748	      /* Overload the bitstream here */
749	      for (size_t bit_index = 0; bit_index < lut_bitstream.size();
750	           ++bit_index) {
751	        VTR_ASSERT('0' == fixed_bitstream[bit_index] ||
752	                   '1' == fixed_bitstream[bit_index]);
753	        lut_bitstream[bit_index + start_index] =
754	          ('1' == fixed_bitstream[bit_index]);
755	      }
756	    }
757	  }
758	
759	  /* Generate bitstream for mode-select ports */
760	  if (0 != lut_mode_select_ports.size()) {
761	    std::vector<bool> mode_select_bitstream;
762	    if (true == physical_pb.valid_pb_id(lut_pb_id)) {
763	      mode_select_bitstream = generate_mode_select_bitstream(
764	        physical_pb.mode_bits(lut_pb_id),
765	        device_annotation.pb_type_mode_bits(lut_pb_type));
766	
767	      /* If the physical pb contains fixed mode-select bitstream, overload here
768	       */
769	      for (const auto& fix_bitstrm :
770	           physical_pb.fixed_mode_select_bitstreams(lut_pb_id)) {
771	        std::string fixed_mode_select_bitstream = fix_bitstrm.content;
772	        size_t mode_bits_start_index = fix_bitstrm.offset;
773	        /* Ensure the length matches!!! */
774	        if (mode_select_bitstream.size() - mode_bits_start_index <
775	            fixed_mode_select_bitstream.size()) {
776	          VTR_LOG_ERROR(
777	            "Unmatched length of fixed mode_select_bitstream %s!Expected to be "
778	            "less than %ld bits\n",
779	            fixed_mode_select_bitstream.c_str(),
780	            mode_select_bitstream.size() - mode_bits_start_index);
781	          exit(1);
782	        }
783	        /* Overload the bitstream here */
784	        for (size_t bit_index = 0;
785	             bit_index < fixed_mode_select_bitstream.size(); ++bit_index) {
786	          VTR_ASSERT('0' == fixed_mode_select_bitstream[bit_index] ||
787	                     '1' == fixed_mode_select_bitstream[bit_index]);
788	          mode_select_bitstream[bit_index + mode_bits_start_index] =
789	            ('1' == fixed_mode_select_bitstream[bit_index]);
790	        }
791	      }
792	    } else { /* get default mode_bits */
793	      mode_select_bitstream = generate_mode_select_bitstream(
794	        device_annotation.pb_type_mode_bits(lut_pb_type));
795	    }
796	
797	    /* Conjunct the mode-select bitstream to the lut bitstream */
798	    for (const bool& bit : mode_select_bitstream) {
799	      lut_bitstream.push_back(bit);
800	    }
801	  }
802	
803	  /* Ensure the length of bitstream matches the side of memory circuits */
804	  std::vector<CircuitModelId> sram_models =
805	    find_circuit_sram_models(circuit_lib, lut_model);
806	  VTR_ASSERT(1 == sram_models.size());
807	  std::string mem_block_name = generate_memory_module_name(
808	    circuit_lib, lut_model, sram_models[0], std::string(MEMORY_MODULE_POSTFIX));
809	  ModuleId mem_module = module_manager.find_module(mem_block_name);
810	  VTR_ASSERT(true == module_manager.valid_module_id(mem_module));
811	  ModulePortId mem_out_port_id = module_manager.find_module_port(
812	    mem_module, generate_configurable_memory_data_out_name());
813	  VTR_ASSERT(
814	    lut_bitstream.size() ==
815	    module_manager.module_port(mem_module, mem_out_port_id).get_width());
816	
817	  /* If there is a feedthrough module, we should consider the scoreboard */
818	  std::string feedthru_mem_block_name =
819	    generate_memory_module_name(circuit_lib, lut_model, sram_models[0],
820	                                std::string(MEMORY_MODULE_POSTFIX), true);
821	  ModuleId feedthru_mem_module =
822	    module_manager.find_module(feedthru_mem_block_name);
823	  if (module_manager.valid_module_id(feedthru_mem_module)) {
824	    auto result = grouped_mem_inst_scoreboard.find(mem_block_name);
825	    if (result == grouped_mem_inst_scoreboard.end()) {
826	      /* Update scoreboard */
827	      grouped_mem_inst_scoreboard[mem_block_name] = 0;
828	    } else {
829	      grouped_mem_inst_scoreboard[mem_block_name]++;
830	      mem_block_name = generate_instance_name(
831	        mem_block_name, grouped_mem_inst_scoreboard[mem_block_name]);
832	    }
833	  }
834	
835	  /* Create a block for the bitstream which corresponds to the memory module
836	   * associated to the LUT */
837	  ConfigBlockId mem_block = bitstream_manager.add_block(mem_block_name);
838	  bitstream_manager.add_child_block(parent_configurable_block, mem_block);
839	
840	  VTR_LOGV(verbose, "Added %lu bits to '%s' under '%s'\n", lut_bitstream.size(),
841	           bitstream_manager.block_name(mem_block).c_str(),
842	           bitstream_manager.block_name(parent_configurable_block).c_str());
843	
844	  /* Add the bitstream to the bitstream manager */
845	  bitstream_manager.add_block_bits(mem_block, lut_bitstream);
846	}
