848	/********************************************************************
849	 * This function generates bitstream for a physical block, which is
850	 * a child block of a grid
851	 * This function will follow a recursive way in generating bitstreams
852	 * It will follow the same sequence in visiting all the sub blocks
853	 * in a physical as we did during module generation
854	 *
855	 * Note: if you want to bind your bitstream with a FPGA fabric generated by
856	 *FPGA-X2P Please follow the same sequence in visiting pb_graph nodes!!! For
857	 *more details, you may refer to function rec_build_physical_block_modules()
858	 *******************************************************************/
859	static void rec_build_physical_block_bitstream(
860	  BitstreamManager& bitstream_manager,
861	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
862	  const ConfigBlockId& parent_configurable_block,
863	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
864	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
865	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
866	  const VprBitstreamAnnotation& bitstream_annotation, const e_side& border_side,
867	  const PhysicalPb& physical_pb, const PhysicalPbId& pb_id,
868	  t_pb_graph_node* physical_pb_graph_node, const size_t& pb_graph_node_index,
869	  const bool& pcf_mode_specified, const std::string& unused_mux_config,
870	  const bool& verbose) {
871	  /* Get the physical pb_type that is linked to the pb_graph node */
872	  t_pb_type* physical_pb_type = physical_pb_graph_node->pb_type;
873	
874	  /* Find the mode that define_idle_mode*/
875	  t_mode* physical_mode = device_annotation.physical_mode(physical_pb_type);
876	
877	  /* Early exit if this parent module has no configurable child modules */
878	  std::string pb_module_name =
879	    generate_physical_block_module_name(physical_pb_type);
880	  pb_module_name = module_name_map.name(pb_module_name);
881	  ModuleId pb_module = module_manager.find_module(pb_module_name);
882	  VTR_ASSERT(true == module_manager.valid_module_id(pb_module));
883	
884	  /* Skip module with no configurable children */
885	  if (0 == module_manager.num_configurable_children(
886	             pb_module, ModuleManager::e_config_child_type::LOGICAL)) {
887	    return;
888	  }
889	
890	  /* Create a block for the physical block under the grid block in bitstream
891	   * manager */
892	  std::string pb_block_name = generate_physical_block_instance_name(
893	    physical_pb_type, pb_graph_node_index);
894	  /* If there are no physical memory blocks under the current module, use the
895	   * previous module, which is the physical memory block */
896	  ConfigBlockId pb_configurable_block = parent_configurable_block;
897	  if (0 < module_manager.num_configurable_children(
898	            pb_module, ModuleManager::e_config_child_type::PHYSICAL)) {
899	    pb_configurable_block = bitstream_manager.add_block(pb_block_name);
900	    bitstream_manager.add_child_block(parent_configurable_block,
901	                                      pb_configurable_block);
902	    /* Reserve child blocks for new created block */
903	    bitstream_manager.reserve_child_blocks(
904	      parent_configurable_block,
905	      count_module_manager_module_configurable_children(
906	        module_manager, pb_module,
907	        ModuleManager::e_config_child_type::PHYSICAL));
908	  }
909	
910	  /* Recursively finish all the child pb_types*/
911	  if (false == is_primitive_pb_type(physical_pb_type)) {
912	    for (int ipb = 0; ipb < physical_mode->num_pb_type_children; ++ipb) {
913	      for (int jpb = 0; jpb < physical_mode->pb_type_children[ipb].num_pb;
914	           ++jpb) {
915	        PhysicalPbId child_pb = PhysicalPbId::INVALID();
916	        /* Find the child pb that is mapped, and the mapping info is not stored
917	         * in the physical mode ! */
918	        if (true == physical_pb.valid_pb_id(pb_id)) {
919	          child_pb = physical_pb.child(
920	            pb_id, &(physical_mode->pb_type_children[ipb]), jpb);
921	          VTR_ASSERT(true == physical_pb.valid_pb_id(child_pb));
922	        }
923	        /* Go recursively */
924	        rec_build_physical_block_bitstream(
925	          bitstream_manager, grouped_mem_inst_scoreboard, pb_configurable_block,
926	          module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
927	          device_annotation, bitstream_annotation, border_side, physical_pb,
928	          child_pb,
929	          &(physical_pb_graph_node
930	              ->child_pb_graph_nodes[physical_mode->index][ipb][jpb]),
931	          jpb, pcf_mode_specified, unused_mux_config, verbose);
932	      }
933	    }
934	  }
935	
936	  /* Check if this has defined a circuit_model*/
937	  if (true == is_primitive_pb_type(physical_pb_type)) {
938	    CircuitModelId primitive_circuit_model =
939	      device_annotation.pb_type_circuit_model(physical_pb_type);
940	    VTR_ASSERT(CircuitModelId::INVALID() != primitive_circuit_model);
941	    switch (circuit_lib.model_type(primitive_circuit_model)) {
942	      case CIRCUIT_MODEL_LUT:
943	        /* Special case for LUT !!!
944	         * Mapped logical block information is stored in child_pbs of this pb!!!
945	         */
946	        build_lut_bitstream(bitstream_manager, grouped_mem_inst_scoreboard,
947	                            pb_configurable_block, device_annotation,
948	                            module_manager, circuit_lib, mux_lib, physical_pb,
949	                            pb_id, physical_pb_type, verbose);
950	        break;
951	      case CIRCUIT_MODEL_FF:
952	      case CIRCUIT_MODEL_HARDLOGIC:
953	      case CIRCUIT_MODEL_IOPAD:
954	        /* For other types of blocks, we can apply a generic therapy */
955	        build_primitive_bitstream(
956	          bitstream_manager, grouped_mem_inst_scoreboard, pb_configurable_block,
957	          module_manager, circuit_lib, device_annotation, physical_pb, pb_id,
958	          physical_pb_type, bitstream_annotation, pcf_mode_specified, verbose);
959	        break;
960	      default:
961	        VTR_LOGF_ERROR(__FILE__, __LINE__,
962	                       "Unknown circuit model type of pb_type '%s'!\n",
963	                       physical_pb_type->name);
964	        exit(1);
965	    }
966	    /* Finish for primitive node, return */
967	    return;
968	  }
969	
970	  /* Generate the bitstream for the interconnection in this physical block */
971	  build_physical_block_interc_bitstream(
972	    bitstream_manager, grouped_mem_inst_scoreboard, pb_configurable_block,
973	    module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
974	    device_annotation, bitstream_annotation, physical_pb_graph_node,
975	    physical_pb, physical_mode, unused_mux_config, verbose);
976	}
