978	/********************************************************************
979	 * This function generates bitstream for a grid, which could be a
980	 * CLB, a heterogenerous block, an I/O, etc.
981	 * Note that each grid may contain a number of physical blocks,
982	 * this function will iterate over them
983	 *******************************************************************/
984	static void build_physical_block_bitstream(
985	  BitstreamManager& bitstream_manager, const ConfigBlockId& top_block,
986	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
987	  const FabricTile& fabric_tile, const FabricTileId& curr_tile,
988	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
989	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
990	  const VprClusteringAnnotation& cluster_annotation,
991	  const VprPlacementAnnotation& place_annotation,
992	  const VprBitstreamAnnotation& bitstream_annotation, const DeviceGrid& grids,
993	  const size_t& layer, const vtr::Point<size_t>& grid_coord,
994	  const e_side& border_side, const std::string& unused_mux_config,
995	  const bool& verbose) {
996	  /* Create a block for the grid in bitstream manager */
997	  t_physical_tile_type_ptr grid_type = grids.get_physical_type(
998	    t_physical_tile_loc(grid_coord.x(), grid_coord.y(), layer));
999	  std::string grid_module_name_prefix(GRID_MODULE_NAME_PREFIX);
1000	
1001	  /* Early exit if this parent module has no configurable child modules */
1002	  std::string grid_module_name = generate_grid_block_module_name(
1003	    grid_module_name_prefix, std::string(grid_type->name), grid_type->is_io(),
1004	    border_side);
1005	  grid_module_name = module_name_map.name(grid_module_name);
1006	  ModuleId grid_module = module_manager.find_module(grid_module_name);
1007	  VTR_ASSERT(true == module_manager.valid_module_id(grid_module));
1008	
1009	  /* Skip module with no configurable children */
1010	  if (0 == module_manager.num_configurable_children(
1011	             grid_module, ModuleManager::e_config_child_type::LOGICAL)) {
1012	    return;
1013	  }
1014	
1015	  vtr::Point<size_t> grid_coord_in_unique_tile = grid_coord;
1016	  if (fabric_tile.valid_tile_id(curr_tile)) {
1017	    /* For tile modules, need to find the specific instance name under its
1018	     * unique tile */
1019	    grid_coord_in_unique_tile =
1020	      fabric_tile.find_pb_coordinate_in_unique_tile(curr_tile, grid_coord);
1021	  }
1022	  std::string grid_block_name = generate_grid_block_instance_name(
1023	    grid_module_name_prefix, std::string(grid_type->name), grid_type->is_io(),
1024	    border_side, grid_coord_in_unique_tile);
1025	
1026	  ConfigBlockId grid_configurable_block =
1027	    bitstream_manager.add_block(grid_block_name);
1028	  bitstream_manager.add_child_block(top_block, grid_configurable_block);
1029	
1030	  /* Reserve child blocks for new created block */
1031	  bitstream_manager.reserve_child_blocks(
1032	    grid_configurable_block, count_module_manager_module_configurable_children(
1033	                               module_manager, grid_module,
1034	                               ModuleManager::e_config_child_type::PHYSICAL));
1035	
1036	  /* Create a dedicated block for the non-unified configurable child */
1037	  if (!module_manager.unified_configurable_children(grid_module)) {
1038	    VTR_ASSERT(1 ==
1039	               module_manager
1040	                 .configurable_children(
1041	                   grid_module, ModuleManager::e_config_child_type::PHYSICAL)
1042	                 .size());
1043	    std::string phy_mem_instance_name = module_manager.instance_name(
1044	      grid_module,
1045	      module_manager.configurable_children(
1046	        grid_module, ModuleManager::e_config_child_type::PHYSICAL)[0],
1047	      module_manager.configurable_child_instances(
1048	        grid_module, ModuleManager::e_config_child_type::PHYSICAL)[0]);
1049	    ConfigBlockId grid_grouped_config_block =
1050	      bitstream_manager.add_block(phy_mem_instance_name);
1051	    VTR_LOGV(
1052	      verbose,
1053	      "Added grouped configurable memory block '%s' as a child to '%s'\n",
1054	      bitstream_manager.block_name(grid_grouped_config_block).c_str(),
1055	      bitstream_manager.block_name(grid_configurable_block).c_str());
1056	    bitstream_manager.add_child_block(grid_configurable_block,
1057	                                      grid_grouped_config_block);
1058	    grid_configurable_block = grid_grouped_config_block;
1059	  }
1060	
1061	  /* Iterate over the capacity of the grid
1062	   * Now each physical tile may have a number of logical blocks
1063	   * OpenFPGA only considers the physical implementation of the tiles.
1064	   * So, we do not allow multiple equivalent sites to be defined
1065	   * under a physical tile type.
1066	   * If you need different equivalent sites, you can always define
1067	   * it as a mode under a <pb_type>
1068	   */
1069	  std::map<std::string, size_t> grouped_mem_inst_scoreboard;
1070	  for (size_t z = 0; z < place_annotation.grid_blocks(grid_coord).size(); ++z) {
1071	    int sub_tile_index =
1072	      device_annotation.physical_tile_z_to_subtile_index(grid_type, z);
1073	    t_logical_block_type_ptr lb_type =
1074	      device_annotation.physical_equivalent_site(
1075	        grid_type, grid_type->sub_tiles[sub_tile_index].name);
1076	    VTR_ASSERT(lb_type != nullptr);
1077	    bool pcf_mode_specified = false;
1078	    std::array<size_t, 3> pcf_loc = {grid_coord.x(), grid_coord.y(), z};
1079	    if (bitstream_annotation.pcf_coord_pb_type(pcf_loc)) {
1080	      pcf_mode_specified = true;
1081	    }
1082	    /* Bypass empty pb_graph */
1083	    if (nullptr == lb_type->pb_graph_head) {
1084	      continue;
1085	    }
1086	
1087	    if (ClusterBlockId::INVALID() ==
1088	        place_annotation.grid_blocks(grid_coord)[z]) {
1089	      /* Recursively traverse the pb_graph and generate bitstream */
1090	      rec_build_physical_block_bitstream(
1091	        bitstream_manager, grouped_mem_inst_scoreboard, grid_configurable_block,
1092	        module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
1093	        device_annotation, bitstream_annotation, border_side, PhysicalPb(),
1094	        PhysicalPbId::INVALID(), lb_type->pb_graph_head, z, pcf_mode_specified,
1095	        unused_mux_config, verbose);
1096	    } else {
1097	      const PhysicalPb& phy_pb = cluster_annotation.physical_pb(
1098	        place_annotation.grid_blocks(grid_coord)[z]);
1099	
1100	      VTR_LOGV(verbose,
1101	               "Generating bitstream for block (x=%lu, y=%lu, subtile=%lu)\n",
1102	               grid_coord.x(), grid_coord.y(), z);
1103	
1104	      /* Get the top-level node of the pb_graph */
1105	      t_pb_graph_node* pb_graph_head = lb_type->pb_graph_head;
1106	      VTR_ASSERT(nullptr != pb_graph_head);
1107	      const PhysicalPbId& top_pb_id = phy_pb.find_pb(pb_graph_head);
1108	      VTR_ASSERT(phy_pb.valid_pb_id(top_pb_id));
1109	
1110	      /* Recursively traverse the pb_graph and generate bitstream */
1111	      rec_build_physical_block_bitstream(
1112	        bitstream_manager, grouped_mem_inst_scoreboard, grid_configurable_block,
1113	        module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
1114	        device_annotation, bitstream_annotation, border_side, phy_pb, top_pb_id,
1115	        pb_graph_head, z, pcf_mode_specified, unused_mux_config, verbose);
1116	      VTR_LOGV(verbose, "Done\n");
1117	    }
1118	  }
1119	}
1120	
1121	/********************************************************************
1122	 * Top-level function of this file:
1123	 * Generate bitstreams for all the grids, including
1124	 * 1. core grids that sit in the center of the fabric
1125	 * 2. side grids (I/O grids) that sit in the borders for the fabric
1126	 *******************************************************************/
1127	void build_grid_bitstream(
1128	  BitstreamManager& bitstream_manager, const ConfigBlockId& top_block,
1129	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
1130	  const FabricTile& fabric_tile, const CircuitLibrary& circuit_lib,
1131	  const MuxLibrary& mux_lib, const DeviceGrid& grids, const size_t& layer,
1132	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
1133	  const VprClusteringAnnotation& cluster_annotation,
1134	  const VprPlacementAnnotation& place_annotation,
1135	  const VprBitstreamAnnotation& bitstream_annotation,
1136	  const std::string& unused_mux_config, const bool& verbose) {
1137	  VTR_LOGV(verbose, "Generating bitstream for core grids...");
1138	
1139	  /* Generate bitstream for the core logic block one by one */
1140	  for (size_t ix = 1; ix < grids.width() - 1; ++ix) {
1141	    for (size_t iy = 1; iy < grids.height() - 1; ++iy) {
1142	      t_physical_tile_loc phy_tile_loc(ix, iy, layer);
1143	      /* Bypass EMPTY grid */
1144	      if (true == is_empty_type(grids.get_physical_type(phy_tile_loc))) {
1145	        continue;
1146	      }
1147	      /* Skip width > 1 or height > 1 tiles (mostly heterogeneous blocks) */
1148	      if ((0 < grids.get_width_offset(phy_tile_loc)) ||
1149	          (0 < grids.get_height_offset(phy_tile_loc))) {
1150	        continue;
1151	      }
1152	      /* Add a grid module to top_module*/
1153	      vtr::Point<size_t> grid_coord(ix, iy);
1154	      /* TODO: If the fabric tile is not empty, find the tile module and create
1155	       * the block accordingly. Also to support future hierarchy changes, when
1156	       * creating the blocks, trace backward until reach the current top block.
1157	       * If any block is missing during the back tracing, create it. */
1158	      ConfigBlockId parent_block = top_block;
1159	      FabricTileId curr_tile =
1160	        fabric_tile.find_tile_by_pb_coordinate(grid_coord);
1161	      if (fabric_tile.valid_tile_id(curr_tile)) {
1162	        vtr::Point<size_t> tile_coord = fabric_tile.tile_coordinate(curr_tile);
1163	        std::string tile_inst_name = generate_tile_module_name(tile_coord);
1164	        parent_block = bitstream_manager.find_or_create_child_block(
1165	          top_block, tile_inst_name);
1166	        VTR_LOGV(verbose,
1167	                 "Add configurable block '%s' as a child under configurable "
1168	                 "block '%s'\n",
1169	                 tile_inst_name.c_str(),
1170	                 bitstream_manager.block_name(top_block).c_str());
1171	      }
1172	
1173	      build_physical_block_bitstream(
1174	        bitstream_manager, parent_block, module_manager, module_name_map,
1175	        fabric_tile, curr_tile, circuit_lib, mux_lib, atom_ctx,
1176	        device_annotation, cluster_annotation, place_annotation,
1177	        bitstream_annotation, grids, layer, grid_coord, NUM_2D_SIDES,
1178	        unused_mux_config, verbose);
1179	    }
1180	  }
1181	  VTR_LOGV(verbose, "Done\n");
1182	
1183	  VTR_LOGV(verbose, "Generating bitstream for I/O grids...");
1184	
1185	  /* Create the coordinate range for each side of FPGA fabric */
1186	  std::map<e_side, std::vector<vtr::Point<size_t>>> io_coordinates =
1187	    generate_perimeter_grid_coordinates(grids);
1188	
1189	  /* Add instances of I/O grids to top_module */
1190	  for (const e_side& io_side : FPGA_SIDES_CLOCKWISE) {
1191	    for (const vtr::Point<size_t>& io_coordinate : io_coordinates[io_side]) {
1192	      t_physical_tile_loc phy_tile_loc(io_coordinate.x(), io_coordinate.y(),
1193	                                       layer);
1194	      /* Bypass EMPTY grid */
1195	      if (true == is_empty_type(grids.get_physical_type(phy_tile_loc))) {
1196	        continue;
1197	      }
1198	      /* Skip height > 1 tiles (mostly heterogeneous blocks) */
1199	      if ((0 < grids.get_width_offset(phy_tile_loc)) ||
1200	          (0 < grids.get_height_offset(phy_tile_loc))) {
1201	        continue;
1202	      }
1203	      /* TODO: If the fabric tile is not empty, find the tile module and create
1204	       * the block accordingly. Also to support future hierarchy changes, when
1205	       * creating the blocks, trace backward until reach the current top block.
1206	       * If any block is missing during the back tracing, create it. */
1207	      ConfigBlockId parent_block = top_block;
1208	      FabricTileId curr_tile =
1209	        fabric_tile.find_tile_by_pb_coordinate(io_coordinate);
1210	      if (fabric_tile.valid_tile_id(curr_tile)) {
1211	        vtr::Point<size_t> tile_coord = fabric_tile.tile_coordinate(curr_tile);
1212	        std::string tile_inst_name = generate_tile_module_name(tile_coord);
1213	        parent_block = bitstream_manager.find_or_create_child_block(
1214	          top_block, tile_inst_name);
1215	        VTR_LOGV(verbose,
1216	                 "Add configurable block '%s' as a child under configurable "
1217	                 "block '%s'\n",
1218	                 tile_inst_name.c_str(),
1219	                 bitstream_manager.block_name(parent_block).c_str());
1220	      }
1221	
1222	      build_physical_block_bitstream(
1223	        bitstream_manager, parent_block, module_manager, module_name_map,
1224	        fabric_tile, curr_tile, circuit_lib, mux_lib, atom_ctx,
1225	        device_annotation, cluster_annotation, place_annotation,
1226	        bitstream_annotation, grids, layer, io_coordinate, io_side,
1227	        unused_mux_config, verbose);
1228	    }
1229	  }
1230	  VTR_LOGV(verbose, "Done\n");
1231	}
1232	
1233	} /* end namespace openfpga */
