20	/********************************************************************
21	 * Find the default path id of a MUX
22	 * This is applied when the path id specified is DEFAULT_PATH_ID,
23	 * which is not correlated to the MUX implementation
24	 * This function is binding the default path id to the implemented structure
25	 * 1. If the MUX has a constant input, the default path id will be
26	 *    directed to the last input of the MUX, which is the constant input
27	 * 2. If the MUX does not have a constant input, the default path id
28	 *    will the first input of the MUX.
29	 *
30	 * Restriction:
31	 *   we assume the default path is the first input of the MUX
32	 *   Change if this is not what you want
33	 *******************************************************************/
34	size_t find_mux_default_path_id(const CircuitLibrary& circuit_lib,
35	                                const CircuitModelId& mux_model,
36	                                const size_t& mux_size,
37	                                const std::string& unused_mux_config) {
38	  size_t default_path_id;
39	
40	  /* Handle unused_mux_config to determine default path selection strategy */
41	
42	  if (unused_mux_config == "first") {
43	    default_path_id = 0;
44	  } else if (unused_mux_config == "last") {
45	    default_path_id = mux_size - 1;
46	  } else if (unused_mux_config == "auto" ||
47	             unused_mux_config == "unused_input") {
48	    if (true == circuit_lib.mux_add_const_input(mux_model)) {
49	      default_path_id = mux_size - 1;
50	    } else {
51	      default_path_id = DEFAULT_MUX_PATH_ID;
52	    }
53	  } else {
54	    VTR_ASSERT_MSG(
55	      false,
56	      ("Invalid unused_mux_config parameter: " + unused_mux_config).c_str());
57	  }
58	  return default_path_id;
59	}
60	
61	/********************************************************************
62	 * This function generates bitstream for a CMOS routing multiplexer
63	 * Thanks to MuxGraph object has already describe the internal multiplexing
64	 * structure, bitstream generation is simply done by routing the signal
65	 * to from a given input to the output
66	 * All the memory bits can be generated by an API of MuxGraph
67	 *
68	 * To be generic, this function only returns a vector bit values
69	 * without touching an bitstream-relate data structure
70	 *******************************************************************/
71	static std::vector<bool> build_cmos_mux_bitstream(
72	  const CircuitLibrary& circuit_lib, const CircuitModelId& mux_model,
73	  const MuxLibrary& mux_lib, const size_t& mux_size, const int& path_id,
74	  const std::string& unused_mux_config) {
75	  /* Note that the size of implemented mux could be different than the mux size
76	   * we see here, due to the constant inputs We will find the input size of
77	   * implemented MUX and fetch the graph-based representation in MUX library
78	   */
79	  size_t implemented_mux_size =
80	    find_mux_implementation_num_inputs(circuit_lib, mux_model, mux_size);
81	  /* Note that the mux graph is indexed using datapath MUX size!!!! */
82	  MuxId mux_graph_id = mux_lib.mux_graph(mux_model, mux_size);
83	  if (!mux_lib.valid_mux_id(mux_graph_id)) {
84	    VTR_ASSERT(mux_lib.valid_mux_id(mux_graph_id));
85	  }
86	  const MuxGraph mux_graph = mux_lib.mux_graph(mux_graph_id);
87	
88	  size_t datapath_id = path_id;
89	
90	  /* Find the path_id related to the implementation */
91	  if (DEFAULT_PATH_ID == path_id) {
92	    datapath_id = find_mux_default_path_id(
93	      circuit_lib, mux_model, implemented_mux_size, unused_mux_config);
94	  } else {
95	    VTR_ASSERT(datapath_id < mux_size);
96	  }
97	  /* Path id should makes sense */
98	  VTR_ASSERT(datapath_id < mux_graph.inputs().size());
99	  /* We should have only one output for this MUX! */
100	  VTR_ASSERT(1 == mux_graph.outputs().size());
101	
102	  /* Generate the memory bits */
103	  vtr::vector<MuxMemId, bool> raw_bitstream = mux_graph.decode_memory_bits(
104	    MuxInputId(datapath_id), mux_graph.output_id(mux_graph.outputs()[0]));
105	
106	  std::vector<bool> mux_bitstream;
107	  for (const bool& bit : raw_bitstream) {
108	    mux_bitstream.push_back(bit);
109	  }
110	
111	  /* Consider local encoder support, we need further encode the bitstream */
112	  if (false == circuit_lib.mux_use_local_encoder(mux_model)) {
113	    return mux_bitstream;
114	  }
115	
116	  /* Clear the mux_bitstream, we need to apply encoding */
117	  mux_bitstream.clear();
118	
119	  /* Encode the memory bits level by level,
120	   * One local encoder is used for each level of multiplexers
121	   */
122	  for (const size_t& level : mux_graph.levels()) {
123	    /* The encoder will convert the path_id to a binary number
124	     * For example: when path_id=3 (use the 4th input), using a 2-input encoder
125	     * the sram_bits will be the 2-digit binary number of 3: 10
126	     */
127	    std::vector<size_t> encoder_data;
128	
129	    /* Exception: there is only 1 memory at this level, bitstream will not be
130	     * changed!!! */
131	    if (1 == mux_graph.memories_at_level(level).size()) {
132	      mux_bitstream.push_back(
133	        raw_bitstream[mux_graph.memories_at_level(level)[0]]);
134	      continue;
135	    }
136	
137	    /* Otherwise: we follow a regular recipe */
138	    for (size_t mem_index = 0;
139	         mem_index < mux_graph.memories_at_level(level).size(); ++mem_index) {
140	      /* Conversion rule: true = 1, false = 0 */
141	      if (true ==
142	          raw_bitstream[mux_graph.memories_at_level(level)[mem_index]]) {
143	        encoder_data.push_back(mem_index);
144	      }
145	    }
146	    /* There should be at most one '1' */
147	    VTR_ASSERT((0 == encoder_data.size()) || (1 == encoder_data.size()));
148	    /* Convert to encoded bits */
149	    std::vector<size_t> encoder_addr;
150	    if (0 == encoder_data.size()) {
151	      encoder_addr =
152	        itobin_vec(0, find_mux_local_decoder_addr_size(
153	                        mux_graph.memories_at_level(level).size()));
154	    } else {
155	      VTR_ASSERT(1 == encoder_data.size());
156	      encoder_addr = itobin_vec(encoder_data[0],
157	                                find_mux_local_decoder_addr_size(
158	                                  mux_graph.memories_at_level(level).size()));
159	    }
160	    /* Build final mux bitstream */
161	    for (const size_t& bit : encoder_addr) {
162	      mux_bitstream.push_back(1 == bit);
163	    }
164	  }
165	
166	  return mux_bitstream;
167	}
