169	/********************************************************************
170	 * This function generates bitstream for a routing multiplexer
171	 * supporting both CMOS and ReRAM multiplexer designs
172	 *******************************************************************/
173	std::vector<bool> build_mux_bitstream(const CircuitLibrary& circuit_lib,
174	                                      const CircuitModelId& mux_model,
175	                                      const MuxLibrary& mux_lib,
176	                                      const size_t& mux_size,
177	                                      const int& path_id,
178	                                      const std::string& unused_mux_config) {
