15	 * This function aims to find out all the pb_graph_pins that drive
16	 * a given pb_graph pin w.r.t. a given interconnect definition
17	 *******************************************************************/
18	std::vector<t_pb_graph_pin*> pb_graph_pin_inputs(
19	  t_pb_graph_pin* pb_graph_pin, t_interconnect* selected_interconnect) {
20	  std::vector<t_pb_graph_pin*> inputs;
21	
22	  /* Search the input edges only, stats on the size of MUX we may need (fan-in)
23	   */
24	  for (int iedge = 0; iedge < pb_graph_pin->num_input_edges; ++iedge) {
25	    /* We care the only edges in the selected mode */
26	    if (selected_interconnect !=
27	        pb_graph_pin->input_edges[iedge]->interconnect) {
28	      continue;
29	    }
30	    for (int ipin = 0; ipin < pb_graph_pin->input_edges[iedge]->num_input_pins;
31	         ++ipin) {
32	      /* Ensure that the pin is unique in the list */
33	      if (inputs.end() !=
34	          std::find(inputs.begin(), inputs.end(),
35	                    pb_graph_pin->input_edges[iedge]->input_pins[ipin])) {
36	        continue;
37	      }
38	      /* Unique pin, push to the vector */
39	      inputs.push_back(pb_graph_pin->input_edges[iedge]->input_pins[ipin]);
40	    }
41	  }
42	
43	  return inputs;
44	}
