46	/********************************************************************
47	 * This function aims to find out the interconnect that drives
48	 * a given pb_graph pin when operating in a select mode
49	 *******************************************************************/
50	t_interconnect* pb_graph_pin_interc(t_pb_graph_pin* pb_graph_pin,
51	                                    t_mode* selected_mode) {
52	  t_interconnect* interc = nullptr;
53	
54	  /* Search the input edges only, stats on the size of MUX we may need (fan-in)
55	   */
56	  for (int iedge = 0; iedge < pb_graph_pin->num_input_edges; ++iedge) {
57	    /* We care the only edges in the selected mode */
58	    if (selected_mode !=
59	        pb_graph_pin->input_edges[iedge]->interconnect->parent_mode) {
60	      continue;
61	    }
62	    /* There should be one unique interconnect to be found! */
63	    if (nullptr != interc) {
64	      VTR_ASSERT(interc == pb_graph_pin->input_edges[iedge]->interconnect);
65	    } else {
66	      interc = pb_graph_pin->input_edges[iedge]->interconnect;
67	    }
68	  }
69	
70	  return interc;
71	}
