73	/********************************************************************
74	 * This function identifies whether the interconnect that drives a given
75	 * pb_graph pin (in a selected mode) is a bus-based multiplexer, i.e. the
76	 * <mux bus="true"/> interconnect in the VPR architecture. For such an
77	 * interconnect every bit of the output bus must select the same input port,
78	 * and all the per-bit multiplexers are controlled by a single shared selector.
79	 *******************************************************************/
80	bool is_pb_graph_pin_bus_interc(t_pb_graph_pin* pb_graph_pin,
81	                                t_mode* selected_mode) {
82	  t_interconnect* interc = pb_graph_pin_interc(pb_graph_pin, selected_mode);
83	  if (nullptr == interc) {
84	    return false;
85	  }
86	  return interc->bus;
87	}
