89	/********************************************************************
90	 * This function aims to find all the sink pb_graph_pins that are driven by a
91	 * given interconnect (in a selected mode), starting from one of its sink pins.
92	 * The pins are collected from the same port as the given destination pin and
93	 * returned ordered by their pin index in the port (i.e. by bus bit index).
94	 * The first element is therefore the lowest-indexed bit, which we use as the
95	 * representative pin when naming the shared resources of a bus-based mux.
96	 *******************************************************************/
97	std::vector<t_pb_graph_pin*> pb_graph_interc_sink_pins(
98	  t_pb_graph_pin* des_pb_graph_pin, t_interconnect* selected_interconnect,
99	  t_mode* selected_mode) {
100	  std::vector<t_pb_graph_pin*> pins;
101	
102	  t_pb_graph_node* node = des_pb_graph_pin->parent_node;
103	  t_port* des_port = des_pb_graph_pin->port;
104	
105	  /* The pins of a port are stored contiguously in the input/output/clock pin
106	   * array of the node, at the slot given by port_index_by_type. Index straight
107	   * to that port instead of scanning every port of the node. */
108	  t_pb_graph_pin* port_pins = nullptr;
109	  if (OUT_PORT == des_port->type) {
110	    port_pins = node->output_pins[des_port->port_index_by_type];
111	  } else if (des_port->is_clock) {
112	    port_pins = node->clock_pins[des_port->port_index_by_type];
113	  } else {
114	    port_pins = node->input_pins[des_port->port_index_by_type];
115	  }
116	
117	  /* Keep only the pins of this port that are driven by the selected
118	   * interconnect */
119	  for (int ipin = 0; ipin < des_port->num_pins; ++ipin) {
120	    t_pb_graph_pin* pin = &port_pins[ipin];
121	    if (selected_interconnect == pb_graph_pin_interc(pin, selected_mode)) {
122	      pins.push_back(pin);
123	    }
124	  }
125	
126	  return pins;
127	}
128	
129	/********************************************************************
130	 * This function identifies if two pb graph pins share at least one interconnect
131	 *model The two pins should be in the same type of port, for example, both are
132	 *inputs. Each pin may drive a number of outgoing edges while each edge
133	 *represents different interconnect model By iterating over outgoing edges for
134	 *each pin, common interconnect model may be found
135	 *******************************************************************/
136	bool is_pb_graph_pins_share_interc(const t_pb_graph_pin* pinA,
137	                                   const t_pb_graph_pin* pinB) {
138	  if (pinA->port->type != pinB->port->type) {
139	    return false;
140	  }
141	  std::vector<t_interconnect*> pinA_interc_list;
142	  for (auto out_edge : pinA->output_edges) {
143	    if (pinA_interc_list.end() == std::find(pinA_interc_list.begin(),
144	                                            pinA_interc_list.end(),
145	                                            out_edge->interconnect)) {
146	      pinA_interc_list.push_back(out_edge->interconnect);
147	    }
148	  }
149	  for (auto out_edge : pinB->output_edges) {
150	    if (pinA_interc_list.end() != std::find(pinA_interc_list.begin(),
151	                                            pinA_interc_list.end(),
152	                                            out_edge->interconnect)) {
153	      return true;
154	    }
155	  }
156	  return false;
157	}
