195	/********************************************************************
196	 * This function generates bitstream for an interconnection,
197	 * i.e., a routing multiplexer, in a Switch Block
198	 * This function will identify if a node indicates a routing multiplexer
199	 * If not a routing multiplexer, no bitstream is needed here
200	 * If yes, we will generate the bitstream for the routing multiplexer
201	 *******************************************************************/
202	static void build_switch_block_interc_bitstream(
203	  BitstreamManager& bitstream_manager,
204	  const ConfigBlockId& sb_configurable_block,
205	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
206	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
207	  const RRGraphView& rr_graph, const RRGraphInEdges& in_edges,
208	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
209	  const VprRoutingAnnotation& routing_annotation, const RRGSB& rr_gsb,
210	  const RRGSBEdges& gsb_edges, const e_side& chan_side,
211	  const size_t& chan_node_id, const std::string& unused_mux_config,
212	  const bool& verbose) {
213	  std::vector<RRNodeId> driver_rr_nodes;
214	
215	  /* Get the node */
216	  const RRNodeId& cur_rr_node = rr_gsb.get_chan_node(chan_side, chan_node_id);
217	
218	  /* Determine if the interc lies inside a channel wire, that is interc between
219	   * segments */
220	  if (false ==
221	      rr_gsb.is_sb_node_passing_wire(rr_graph, chan_side, chan_node_id)) {
222	    driver_rr_nodes = get_rr_gsb_chan_node_configurable_driver_nodes(
223	      rr_graph, in_edges, rr_gsb, gsb_edges, chan_side, chan_node_id);
224	    /* Special: if there are zero-driver nodes. We skip here */
225	    if (0 == driver_rr_nodes.size()) {
226	      return;
227	    }
228	  }
229	
230	  if ((0 == driver_rr_nodes.size()) || (0 == driver_rr_nodes.size())) {
231	    /* No bitstream generation required by a special direct connection*/
232	    return;
233	  } else if (1 < driver_rr_nodes.size()) {
234	    /* Create the block denoting the memory instances that drives this node in
235	     * Switch Block */
236	    std::string mem_block_name = generate_sb_memory_instance_name(
237	      SWITCH_BLOCK_MEM_INSTANCE_PREFIX, chan_side, chan_node_id,
238	      std::string(""));
239	    ConfigBlockId mux_mem_block = bitstream_manager.add_block(mem_block_name);
240	    bitstream_manager.add_child_block(sb_configurable_block, mux_mem_block);
241	    VTR_LOGV(verbose, "Added '%s' under '%s'\n",
242	             bitstream_manager.block_name(mux_mem_block).c_str(),
243	             bitstream_manager.block_name(sb_configurable_block).c_str());
244	    /* This is a routing multiplexer! Generate bitstream */
245	    build_switch_block_mux_bitstream(
246	      bitstream_manager, mux_mem_block, module_manager, module_name_map,
247	      circuit_lib, mux_lib, rr_graph, in_edges, cur_rr_node, driver_rr_nodes,
248	      gsb_edges.get_chan_node_in_edges(rr_gsb, in_edges, chan_side,
249	                                       chan_node_id),
250	      atom_ctx, device_annotation, routing_annotation, unused_mux_config,
251	      verbose);
252	  } /*Nothing should be done else*/
253	}
