255	/********************************************************************
256	 * This function generates bitstream for a routing multiplexer
257	 * in a Connection block
258	 * This function will identify if a node indicates a routing multiplexer
259	 * If not a routing multiplexer, no bitstream is needed here
260	 * If yes, we will generate the bitstream for the routing multiplexer
261	 *******************************************************************/
262	static void build_connection_block_mux_bitstream(
263	  BitstreamManager& bitstream_manager, const ConfigBlockId& mux_mem_block,
264	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
265	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
266	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
267	  const VprRoutingAnnotation& routing_annotation, const RRGraphView& rr_graph,
268	  const RRGraphInEdges& in_edges, const RRGSB& rr_gsb,
269	  const RRGSBEdges& gsb_edges, const e_side& cb_ipin_side,
270	  const size_t& ipin_index, const std::string& unused_mux_config,
271	  const bool& verbose) {
272	  RRNodeId src_rr_node = rr_gsb.get_ipin_node(cb_ipin_side, ipin_index);
273	  /* Find drive_rr_nodes*/
274	  std::vector<RREdgeId> driver_rr_edges = gsb_edges.get_ipin_node_in_edges(
275	    rr_gsb, in_edges, cb_ipin_side, ipin_index);
276	  size_t datapath_mux_size = driver_rr_edges.size();
277	
278	  /* Cache input and output nets */
279	  std::vector<ClusterNetId> input_nets;
280	  ClusterNetId output_net = routing_annotation.rr_node_net(src_rr_node);
281	  for (const RREdgeId& edge : driver_rr_edges) {
282	    RRNodeId driver_node = rr_graph.edge_src_node(edge);
283	    input_nets.push_back(routing_annotation.rr_node_net(driver_node));
284	  }
285	
286	  /* Configuration bits for MUX*/
287	  int path_id = DEFAULT_PATH_ID;
288	  int edge_index = 0;
289	
290	  /* Find which path is connected to the output of this routing multiplexer
291	   * Two conditions to be considered:
292	   * - There is no net mapped to src_rr_node: we use default path id
293	   * - There is a net mapped to src_rr_node: we find the path id
294	   */
295	  if (ClusterNetId::INVALID() != output_net) {
296	    for (const RREdgeId& edge : driver_rr_edges) {
297	      RRNodeId driver_node = rr_graph.edge_src_node(edge);
298	      /* We must have a valid previous node that is supposed to drive the source
299	       * node! */
300	      VTR_ASSERT(routing_annotation.rr_node_prev_node(src_rr_node));
301	      if ((routing_annotation.rr_node_net(driver_node) == output_net) &&
302	          (driver_node == routing_annotation.rr_node_prev_node(src_rr_node))) {
303	        path_id = edge_index;
304	        break;
305	      }
306	      edge_index++;
307	    }
308	  }
309	
310	  /* Ensure that our path id makes sense! */
311	  VTR_ASSERT(
312	    (DEFAULT_PATH_ID == path_id) ||
313	    ((DEFAULT_PATH_ID < path_id) && (path_id < (int)datapath_mux_size)));
314	
315	  /* Find the circuit model id of the mux, we need its design technology which
316	   * matters the bitstream generation */
317	  std::vector<RRSwitchId> driver_switches;
318	  for (const RREdgeId& edge : driver_rr_edges) {
319	    RRSwitchId sw = RRSwitchId(rr_graph.edge_switch(edge));
320	    if (driver_switches.end() ==
321	        std::find(driver_switches.begin(), driver_switches.end(), sw)) {
322	      driver_switches.push_back(sw);
323	    }
324	  }
325	  VTR_ASSERT_MSG(1 <= driver_switches.size(),
326	                 ("There should be at least one driver switch for " +
327	                  std::to_string(size_t(src_rr_node)))
328	                   .c_str());
329	  /* Iterate over driver switches to find a common switch that can be used */
330	  CircuitModelId switch_index =
331	    device_annotation.rr_switch_circuit_model(driver_switches[0]);
332	  for (size_t i = 1; i < driver_switches.size(); ++i) {
333	    VTR_ASSERT_MSG(device_annotation.rr_switch_circuit_model(
334	                     driver_switches[i]) == switch_index,
335	                   ("All driver switches of " +
336	                    std::to_string(size_t(src_rr_node)) + " must be the same")
337	                     .c_str());
338	  }
339	  CircuitModelId mux_model =
340	    device_annotation.rr_switch_circuit_model(driver_switches[0]);
341	
342	  /* Generate bitstream depend on both technology and structure of this MUX */
343	  std::vector<bool> mux_bitstream =
344	    build_mux_bitstream(circuit_lib, mux_model, mux_lib, datapath_mux_size,
345	                        path_id, unused_mux_config);
346	
347	  /* Find the module in module manager and ensure the bitstream size matches! */
348	  std::string mem_module_name =
349	    generate_mux_subckt_name(circuit_lib, mux_model, datapath_mux_size,
350	                             std::string(MEMORY_MODULE_POSTFIX));
351	  mem_module_name = module_name_map.name(mem_module_name);
352	  ModuleId mux_mem_module = module_manager.find_module(mem_module_name);
353	  VTR_ASSERT(true == module_manager.valid_module_id(mux_mem_module));
354	  ModulePortId mux_mem_out_port_id = module_manager.find_module_port(
355	    mux_mem_module, generate_configurable_memory_data_out_name());
356	  VTR_ASSERT(mux_bitstream.size() ==
357	             module_manager.module_port(mux_mem_module, mux_mem_out_port_id)
358	               .get_width());
359	
360	  VTR_LOGV(
361	    verbose, "Added %lu bits to '%s' under '%s'\n", mux_bitstream.size(),
362	    bitstream_manager.block_name(mux_mem_block).c_str(),
363	    bitstream_manager.block_name(bitstream_manager.block_parent(mux_mem_block))
364	      .c_str());
365	
366	  /* Add the bistream to the bitstream manager */
367	  bitstream_manager.add_block_bits(mux_mem_block, mux_bitstream);
368	  /* Record path ids, input and output nets */
369	  bitstream_manager.add_path_id_to_block(mux_mem_block, path_id);
370	
371	  /* Add input nets */
372	  bool need_splitter = false;
373	  std::string input_net_ids;
374	  for (const ClusterNetId& input_net : input_nets) {
375	    /* Add a space as a splitter*/
376	    if (true == need_splitter) {
377	      input_net_ids += std::string(" ");
378	    }
379	    AtomNetId input_atom_net = atom_ctx.lookup().atom_net(input_net);
380	    if (true == atom_ctx.netlist().valid_net_id(input_atom_net)) {
381	      input_net_ids += atom_ctx.netlist().net_name(input_atom_net);
382	    } else {
383	      input_net_ids += std::string("unmapped");
384	    }
385	    need_splitter = true;
386	  }
387	  bitstream_manager.add_input_net_id_to_block(mux_mem_block, input_net_ids);
388	
389	  /* Add output nets */
390	  std::string output_net_ids;
391	  AtomNetId output_atom_net = atom_ctx.lookup().atom_net(output_net);
392	  if (true == atom_ctx.netlist().valid_net_id(output_atom_net)) {
393	    output_net_ids += atom_ctx.netlist().net_name(output_atom_net);
394	  } else {
395	    output_net_ids += std::string("unmapped");
396	  }
397	  bitstream_manager.add_output_net_id_to_block(mux_mem_block, output_net_ids);
398	}
